// Ported from: src/sql_jsc/mysql/protocol/DecodeBinaryValue.rs
// This file is a Rust-faithful Dafny model of decode_binary_value.  The
// reader, SQLDataCell union, and MySQL primitive reads are represented by
// narrow helper datatypes/functions so the match structure remains close to
// the Rust implementation.

module DecodeBinaryValue {
  const BINARY_CHARSET: int := 63

  datatype JSGlobalObject = JSGlobalObject

  datatype FieldType =
    MYSQL_TYPE_TINY |
    MYSQL_TYPE_SHORT |
    MYSQL_TYPE_INT24 |
    MYSQL_TYPE_LONG |
    MYSQL_TYPE_LONGLONG |
    MYSQL_TYPE_FLOAT |
    MYSQL_TYPE_DOUBLE |
    MYSQL_TYPE_TIME |
    MYSQL_TYPE_DATE |
    MYSQL_TYPE_TIMESTAMP |
    MYSQL_TYPE_DATETIME |
    MYSQL_TYPE_ENUM |
    MYSQL_TYPE_SET |
    MYSQL_TYPE_GEOMETRY |
    MYSQL_TYPE_NEWDECIMAL |
    MYSQL_TYPE_STRING |
    MYSQL_TYPE_VARCHAR |
    MYSQL_TYPE_VAR_STRING |
    MYSQL_TYPE_TINY_BLOB |
    MYSQL_TYPE_MEDIUM_BLOB |
    MYSQL_TYPE_LONG_BLOB |
    MYSQL_TYPE_BLOB |
    MYSQL_TYPE_JSON |
    MYSQL_TYPE_BIT |
    MYSQL_TYPE_OTHER

  datatype CellTag = Raw | Uint4 | Int4 | Uint8 | Int8 | String | Json | Bool | Date | Float8

  datatype CellValue =
    RawValue(data: seq<int>) |
    Uint4Value(uint4: int) |
    Int4Value(int4: int) |
    Uint8Value(uint8: int) |
    Int8Value(int8: int) |
    StringValue(string: seq<int>) |
    JsonValue(json: seq<int>) |
    BoolValue(bool_: int) |
    DateValue(date: int) |
    Float8Bits(bits: int)

  datatype SQLDataCell = SQLDataCell(tag: CellTag, value: CellValue, free_value: int)

  datatype NewReader = NewReader(data: seq<int>, pos: int)

  datatype ReadBytesResult = ReadBytesOk(data: seq<int>, reader: NewReader) | ReadBytesErr(error: string, reader: NewReader)
  datatype ReadIntResult = ReadIntOk(value: int, reader: NewReader) | ReadIntErr(error: string, reader: NewReader)
  datatype DecodeResult = DecodeOk(cell: SQLDataCell, reader: NewReader) | DecodeErr(error: string, reader: NewReader)

  datatype Time = Time(negative: bool, days: int, hours: int, minutes: int, seconds: int)
  datatype TimeResult = TimeOk(time: Time) | TimeErr(error: string)
  datatype DateTime = DateTime(year: int, month: int, day: int, hour: int, minute: int, second: int, microsecond: int)
  datatype DateTimeResult = DateTimeOk(time: DateTime) | DateTimeErr(error: string)

  function ValidReader(reader: NewReader): bool {
    0 <= reader.pos <= |reader.data| && forall i :: 0 <= i < |reader.data| ==> 0 <= reader.data[i] < 256
  }

  function raw(data: seq<int>): SQLDataCell {
    SQLDataCell(Raw, RawValue(data), 0)
  }

  function clone_utf8_wtf_impl(slice: seq<int>): seq<int> {
    slice
  }

  function Pow2(bits: int): int
    requires 0 <= bits
  {
    if bits == 0 then 1 else 2 * Pow2(bits - 1)
  }

  function LeValue(bytes: seq<int>): int
    requires forall i :: 0 <= i < |bytes| ==> 0 <= bytes[i] < 256
  {
    if |bytes| == 0 then 0 else bytes[0] + 256 * LeValue(bytes[1..])
  }

  function Signed(value: int, bits: int): int
    requires 0 <= bits
  {
    if bits == 0 then value else if value >= Pow2(bits - 1) then value - Pow2(bits) else value
  }

  function read(reader: NewReader, len: int): ReadBytesResult
    requires ValidReader(reader)
  {
    if 0 <= len && reader.pos + len <= |reader.data| then
      ReadBytesOk(reader.data[reader.pos..reader.pos + len], NewReader(reader.data, reader.pos + len))
    else
      ReadBytesErr("ShortRead", reader)
  }

  function byte(reader: NewReader): ReadIntResult
    requires ValidReader(reader)
  {
    match read(reader, 1)
    case ReadBytesOk(data, next) => ReadIntOk(data[0], next)
    case ReadBytesErr(error, next) => ReadIntErr(error, next)
  }

  function int_le(reader: NewReader, len: int, signed: bool): ReadIntResult
    requires ValidReader(reader)
    requires 0 <= len
  {
    match read(reader, len)
    case ReadBytesOk(data, next) =>
      var val := LeValue(data);
      ReadIntOk(if signed then Signed(val, 8 * len) else val, next)
    case ReadBytesErr(error, next) => ReadIntErr(error, next)
  }

  function int_u24(reader: NewReader): ReadIntResult
    requires ValidReader(reader)
  {
    int_le(reader, 3, false)
  }

  function int_i24(reader: NewReader): ReadIntResult
    requires ValidReader(reader)
  {
    int_le(reader, 3, true)
  }

  function encode_len_string(reader: NewReader): ReadBytesResult
    requires ValidReader(reader)
  {
    match byte(reader)
    case ReadIntErr(error, next) => ReadBytesErr(error, next)
    case ReadIntOk(first, after_first) =>
      if first < 251 then read(after_first, first)
      else if first == 252 then
        match int_le(after_first, 2, false)
        case ReadIntErr(error, next) => ReadBytesErr(error, next)
        case ReadIntOk(len, after_len) => read(after_len, len)
      else if first == 253 then
        match int_u24(after_first)
        case ReadIntErr(error, next) => ReadBytesErr(error, next)
        case ReadIntOk(len, after_len) => read(after_len, len)
      else if first == 254 then
        match int_le(after_first, 8, false)
        case ReadIntErr(error, next) => ReadBytesErr(error, next)
        case ReadIntOk(len, after_len) => read(after_len, len)
      else
        ReadBytesErr("InvalidLengthEncodedString", after_first)
  }

  function TimeFromData(data: seq<int>): TimeResult
    requires forall i :: 0 <= i < |data| ==> 0 <= data[i] < 256
  {
    if |data| == 8 || |data| == 12 then
      var negative := data[0] != 0;
      var days := LeValue(data[1..5]);
      var hours := data[5];
      var minutes := data[6];
      var seconds := data[7];
      TimeOk(Time(negative, days, hours, minutes, seconds))
    else
      TimeErr("InvalidBinaryValue")
  }

  function DateTimeFromData(data: seq<int>): DateTimeResult
    requires forall i :: 0 <= i < |data| ==> 0 <= data[i] < 256
  {
    if |data| == 4 || |data| == 7 || |data| == 11 then
      var year := LeValue(data[0..2]);
      var month := data[2];
      var day := data[3];
      var hour := if |data| >= 7 then data[4] else 0;
      var minute := if |data| >= 7 then data[5] else 0;
      var second := if |data| >= 7 then data[6] else 0;
      var microsecond := if |data| == 11 then LeValue(data[7..11]) else 0;
      DateTimeOk(DateTime(year, month, day, hour, minute, second, microsecond))
    else
      DateTimeErr("InvalidBinaryValue")
  }

  function JsTimestampFromDateTime(global_object: JSGlobalObject, time: DateTime): int {
    time.year * 10000000000 + time.month * 100000000 + time.day * 1000000 + time.hour * 10000 + time.minute * 100 + time.second
  }

  function TwoDigits(n: int): seq<int>
    requires 0 <= n
  {
    if n < 100 then [48 + n / 10, 48 + n % 10] else ItoaNonNegative(n)
  }

  function ThreeDigits(n: int): seq<int>
    requires 0 <= n
  {
    if n < 1000 then [48 + n / 100, 48 + (n / 10) % 10, 48 + n % 10] else ItoaNonNegative(n)
  }

  function FormatTime(time: Time): seq<int>
  {
    var total_hours := time.hours + time.days * 24;
    var sign := if time.negative then [45] else [];
    if total_hours < 0 || time.minutes < 0 || time.seconds < 0 then
      []
    else if total_hours > 99 then
      sign + ThreeDigits(total_hours) + [58] + TwoDigits(time.minutes) + [58] + TwoDigits(time.seconds)
    else
      sign + TwoDigits(total_hours) + [58] + TwoDigits(time.minutes) + [58] + TwoDigits(time.seconds)
  }

  function ItoaNonNegative(n: int): seq<int>
    requires 0 <= n
  {
    if n < 10 then [48 + n] else ItoaNonNegative(n / 10) + [48 + n % 10]
  }

  function Itoa(n: int): seq<int> {
    if n < 0 then [45] + ItoaNonNegative(-n) else ItoaNonNegative(n)
  }

  function IsStringLike(field_type: FieldType): bool {
    field_type.MYSQL_TYPE_ENUM? || field_type.MYSQL_TYPE_SET? || field_type.MYSQL_TYPE_GEOMETRY? ||
    field_type.MYSQL_TYPE_NEWDECIMAL? || field_type.MYSQL_TYPE_STRING? || field_type.MYSQL_TYPE_VARCHAR? ||
    field_type.MYSQL_TYPE_VAR_STRING? || field_type.MYSQL_TYPE_TINY_BLOB? || field_type.MYSQL_TYPE_MEDIUM_BLOB? ||
    field_type.MYSQL_TYPE_LONG_BLOB? || field_type.MYSQL_TYPE_BLOB?
  }

  function decode_binary_value(
    global_object: JSGlobalObject,
    field_type: FieldType,
    column_length: int,
    raw_: bool,
    bigint: bool,
    unsigned: bool,

