  }

  function IsStringLike(field_type: FieldType): bool {
    field_type.MYSQL_TYPE_ENUM? || field_type.MYSQL_TYPE_SET? || field_type.MYSQL_TYPE_GEOMETRY? ||
    field_type.MYSQL_TYPE_NEWDECIMAL? || field_type.MYSQL_TYPE_STRING? || field_type.MYSQL_TYPE_VARCHAR? ||
    field_type.MYSQL_TYPE_VAR_STRING? || field_type.MYSQL_TYPE_TINY_BLOB? || field_type.MYSQL_TYPE_MEDIUM_BLOB? ||
    field_type.MYSQL_TYPE_LONG_BLOB? || field_type.MYSQL_TYPE_BLOB?
  }

  function decode_binary_value(
    global_object: JSGlobalObject,
    field_type: FieldType,
    column_length: int,
    raw_: bool,
    bigint: bool,
    unsigned: bool,
    binary: bool,
    character_set: int,
    reader: NewReader
  ): DecodeResult
    requires ValidReader(reader)
    requires 0 <= column_length
  {
    match field_type
    case MYSQL_TYPE_TINY => DecodeTiny(raw_, unsigned, reader)
    case MYSQL_TYPE_SHORT => DecodeFixedInt(raw_, unsigned, reader, 2, 16)
    case MYSQL_TYPE_INT24 => DecodeInt24(raw_, unsigned, reader)
    case MYSQL_TYPE_LONG => DecodeFixedInt(raw_, unsigned, reader, 4, 32)
    case MYSQL_TYPE_LONGLONG => DecodeLongLong(raw_, bigint, unsigned, reader)
    case MYSQL_TYPE_FLOAT => DecodeFloat(raw_, reader, 4)
    case MYSQL_TYPE_DOUBLE => DecodeFloat(raw_, reader, 8)
    case MYSQL_TYPE_TIME => DecodeTime(reader)
    case MYSQL_TYPE_DATE => DecodeDateTime(global_object, reader)
    case MYSQL_TYPE_TIMESTAMP => DecodeDateTime(global_object, reader)
    case MYSQL_TYPE_DATETIME => DecodeDateTime(global_object, reader)
    case MYSQL_TYPE_ENUM => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_SET => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_GEOMETRY => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_NEWDECIMAL => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_STRING => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_VARCHAR => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_VAR_STRING => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_TINY_BLOB => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_MEDIUM_BLOB => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_LONG_BLOB => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_BLOB => DecodeStringLike(raw_, binary, character_set, reader)
    case MYSQL_TYPE_JSON => DecodeJson(raw_, reader)
    case MYSQL_TYPE_BIT => DecodeBit(column_length, reader)
    case MYSQL_TYPE_OTHER => DecodeDefault(column_length, reader)
  }

  function DecodeTiny(raw_: bool, unsigned: bool, reader: NewReader): DecodeResult
    requires ValidReader(reader)
  {
    if raw_ then
      match read(reader, 1) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
    else
      match byte(reader) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(val, next) => if unsigned then DecodeOk(SQLDataCell(Uint4, Uint4Value(val), 0), next) else DecodeOk(SQLDataCell(Int4, Int4Value(Signed(val, 8)), 0), next) }
  }

  function DecodeFixedInt(raw_: bool, unsigned: bool, reader: NewReader, len: int, bits: int): DecodeResult
    requires ValidReader(reader)
    requires 0 <= len && 0 <= bits
  {
    if raw_ then
      match read(reader, len) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
    else if unsigned then
      match int_le(reader, len, false) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(value, next) => DecodeOk(SQLDataCell(Uint4, Uint4Value(value), 0), next) }
    else
      match int_le(reader, len, true) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(value, next) => DecodeOk(SQLDataCell(Int4, Int4Value(value), 0), next) }
  }

  function DecodeInt24(raw_: bool, unsigned: bool, reader: NewReader): DecodeResult
    requires ValidReader(reader)
  {
    if raw_ then
      match read(reader, 3) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
    else if unsigned then
      match int_u24(reader) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(value, next) => DecodeOk(SQLDataCell(Uint4, Uint4Value(value), 0), next) }
    else
      match int_i24(reader) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(value, next) => DecodeOk(SQLDataCell(Int4, Int4Value(value), 0), next) }
  }

  function DecodeLongLong(raw_: bool, bigint: bool, unsigned: bool, reader: NewReader): DecodeResult
    requires ValidReader(reader)
  {
    if raw_ then
      match read(reader, 8) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
    else if unsigned then
      match int_le(reader, 8, false) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(val, next) =>
        if val <= 4294967295 then DecodeOk(SQLDataCell(Uint4, Uint4Value(val), 0), next)
        else if bigint then DecodeOk(SQLDataCell(Uint8, Uint8Value(val), 0), next)
        else DecodeOk(SQLDataCell(String, StringValue(clone_utf8_wtf_impl(Itoa(val))), 1), next) }
    else
      match int_le(reader, 8, true) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(val, next) =>
        if -2147483648 <= val && val <= 2147483647 then DecodeOk(SQLDataCell(Int4, Int4Value(val), 0), next)
        else if bigint then DecodeOk(SQLDataCell(Int8, Int8Value(val), 0), next)
        else DecodeOk(SQLDataCell(String, StringValue(clone_utf8_wtf_impl(Itoa(val))), 1), next) }
  }

  function DecodeFloat(raw_: bool, reader: NewReader, len: int): DecodeResult
    requires ValidReader(reader)
    requires 0 <= len
  {
    if raw_ then
      match read(reader, len) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
    else
      match int_le(reader, len, false) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(bits, next) => DecodeOk(SQLDataCell(Float8, Float8Bits(bits), 0), next) }
  }

  function DecodeTime(reader: NewReader): DecodeResult
    requires ValidReader(reader)
  {
    match byte(reader) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(length, after_length) =>
      if length == 0 then
        DecodeOk(SQLDataCell(String, StringValue(clone_utf8_wtf_impl([48, 48, 58, 48, 48, 58, 48, 48])), 1), after_length)
      else if length == 8 || length == 12 then
        match read(after_length, length) { case ReadBytesErr(error, next) => DecodeErr(error, next) case ReadBytesOk(data, next) =>
          match TimeFromData(data) { case TimeErr(error) => DecodeErr(error, next) case TimeOk(time) => DecodeOk(SQLDataCell(String, StringValue(clone_utf8_wtf_impl(FormatTime(time))), 1), next) } }
      else
        DecodeErr("InvalidBinaryValue", after_length) }
  }

  function DecodeDateTime(global_object: JSGlobalObject, reader: NewReader): DecodeResult
    requires ValidReader(reader)
  {
    match byte(reader) { case ReadIntErr(error, next) => DecodeErr(error, next) case ReadIntOk(length, after_length) =>
      if length == 0 then
        DecodeOk(SQLDataCell(Date, DateValue(0), 0), after_length)
      else if length == 11 || length == 7 || length == 4 then
        match read(after_length, length) { case ReadBytesErr(error, next) => DecodeErr(error, next) case ReadBytesOk(data, next) =>
          match DateTimeFromData(data) { case DateTimeErr(error) => DecodeErr(error, next) case DateTimeOk(time) => DecodeOk(SQLDataCell(Date, DateValue(JsTimestampFromDateTime(global_object, time)), 0), next) } }
      else
        DecodeErr("InvalidBinaryValue", after_length) }
  }

  function DecodeStringLike(raw_: bool, binary: bool, character_set: int, reader: NewReader): DecodeResult
    requires ValidReader(reader)
  {
    if raw_ then
      match encode_len_string(reader) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
    else
      match encode_len_string(reader) { case ReadBytesErr(error, next) => DecodeErr(error, next) case ReadBytesOk(string_data, next) =>
        if binary && character_set == BINARY_CHARSET then DecodeOk(raw(string_data), next)
        else DecodeOk(SQLDataCell(String, StringValue(if |string_data| != 0 then clone_utf8_wtf_impl(string_data) else []), 1), next) }
  }

  function DecodeJson(raw_: bool, reader: NewReader): DecodeResult
    requires ValidReader(reader)
  {
    if raw_ then
      match encode_len_string(reader) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
    else
      match encode_len_string(reader) { case ReadBytesErr(error, next) => DecodeErr(error, next) case ReadBytesOk(string_data, next) => DecodeOk(SQLDataCell(Json, JsonValue(if |string_data| != 0 then clone_utf8_wtf_impl(string_data) else []), 1), next) }
  }

  function DecodeBit(column_length: int, reader: NewReader): DecodeResult
    requires ValidReader(reader)
    requires 0 <= column_length
  {
    if column_length == 1 then
      match encode_len_string(reader) { case ReadBytesErr(error, next) => DecodeErr(error, next) case ReadBytesOk(data, next) => DecodeOk(SQLDataCell(Bool, BoolValue(if |data| != 0 && data[0] == 1 then 1 else 0), 0), next) }
    else
      match encode_len_string(reader) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
  }

  function DecodeDefault(column_length: int, reader: NewReader): DecodeResult
    requires ValidReader(reader)
    requires 0 <= column_length
  {
    match read(reader, column_length) { case ReadBytesOk(data, next) => DecodeOk(raw(data), next) case ReadBytesErr(error, next) => DecodeErr(error, next) }
  }

  lemma SanityCheck()
  {
    var global_object := JSGlobalObject;
    var r := NewReader([5], 0);
    assert decode_binary_value(global_object, MYSQL_TYPE_TINY, 1, false, false, false, false, 0, r)
      == DecodeOk(SQLDataCell(Int4, Int4Value(5), 0), NewReader([5], 1));
  }
}

use crate::jsc::JSGlobalObject;
#[allow(unused_imports)]
use crate::mysql::my_sql_value::Value;
use crate::mysql::my_sql_value::{DateTime, Time};
use crate::shared::sql_data_cell::SQLDataCell;
use crate::shared::sql_data_cell::{Tag as CellTag, Value as CellValue};
use bun_sql::mysql::mysql_types as types;
use bun_sql::mysql::mysql_types::FieldType;
use bun_sql::mysql::protocol::new_reader::{NewReader, ReaderContext};

bun_core::declare_scope!(MySQLDecodeBinaryValue, visible);

/// MySQL's "binary" pseudo-charset ID. Columns with this character_set value
/// are true binary types (BINARY, VARBINARY, BLOB), as opposed to string columns
/// with binary collations (e.g., utf8mb4_bin) which have different character_set values.
pub const BINARY_CHARSET: u16 = 63;

// TODO(port): narrow error set
pub fn decode_binary_value<Context: ReaderContext>(
    global_object: &JSGlobalObject,
    field_type: types::FieldType,
    column_length: u32,
    raw: bool,
    bigint: bool,
    unsigned: bool,
    binary: bool,
    character_set: u16,
    reader: NewReader<Context>,
) -> Result<SQLDataCell, bun_core::Error> {
    bun_core::scoped_log!(
        MySQLDecodeBinaryValue,
        "decodeBinaryValue: {}",
        <&'static str>::from(field_type)
    );
    match field_type {
        FieldType::MYSQL_TYPE_TINY => {
            if raw {
                let data = reader.read(1)?;
                return Ok(SQLDataCell::raw(Some(&data)));
            }
            let val = reader.byte()?;
            if unsigned {
                return Ok(SQLDataCell {
                    tag: CellTag::Uint4,
                    value: CellValue { uint4: val as u32 },
                    ..Default::default()
                });
            }
            let ival: i8 = val as i8;
            Ok(SQLDataCell {
                tag: CellTag::Int4,
                value: CellValue { int4: ival as i32 },
                ..Default::default()
            })
        }
        FieldType::MYSQL_TYPE_SHORT => {
            if raw {
                let data = reader.read(2)?;
                return Ok(SQLDataCell::raw(Some(&data)));
            }
            if unsigned {
                return Ok(SQLDataCell {
                    tag: CellTag::Uint4,
                    value: CellValue {
                        uint4: reader.int::<u16>()? as u32,
                    },
                    ..Default::default()
                });
            }
            Ok(SQLDataCell {
                tag: CellTag::Int4,
                value: CellValue {
                    int4: reader.int::<i16>()? as i32,
                },
                ..Default::default()
            })
        }
        FieldType::MYSQL_TYPE_INT24 => {
            if raw {
                let data = reader.read(3)?;
                return Ok(SQLDataCell::raw(Some(&data)));
